import {
    useSignAndExecuteTransaction,
 //   useIotaClient
} from '@iota/dapp-kit';
import { useState } from 'react';
import { Transaction } from '@iota/iota-sdk/transactions';

// ==========================================
// Initialize IOTA Client
// ==========================================
const PACKAGE_ID = '0x1d88735131b46ce072aa45020971d3dc6da53bc936b839b9b03a29c7e5134700';
const MODULE = 'generic_store';

function moveTarget(fn: string) {
  return `${PACKAGE_ID}::${MODULE}::${fn}`;
}
y
function submitTx(
  signAndExecuteTransaction: any,
  tx: Transaction,
  address: string,
  setDigest: (d: string) => void
) {
  tx.setSender(address);

  signAndExecuteTransaction(
    { transaction: tx },
    {
      onSuccess: (res: any) => {
        console.log('TX success', res);
        setDigest(res.digest);
      },
      onError: (err: any) => {
        console.error('TX failed', err);
      },
    }
  );
}
function CreateContainerForm({ address }: { address: string }) {
  const { mutate: signAndExecuteTransaction } = useSignAndExecuteTransaction();
  const [digest, setDigest] = useState('');

  const [form, setForm] = useState({
    externalId: '',
    name: '',
    description: '',
    content: '',
    publicUpdate: true,
    publicAttach: true,
    publicCreateType: true,
    publicPublish: true,
    eventCreate: true,
    eventPublish: true,
    eventAttach: true,
    eventAdd: true,
    eventRemove: true,
    eventUpdate: true,
  });

  const submit = () => {
    const tx = new Transaction();

    tx.moveCall({
      target: moveTarget('create_container'),
      arguments: [
        tx.pure.string(form.externalId),
        tx.pure.string(form.name),
        tx.pure.string(form.description),
        tx.pure.string(form.content),
        tx.pure.bool(form.publicUpdate),
        tx.pure.bool(form.publicAttach),
        tx.pure.bool(form.publicCreateType),
        tx.pure.bool(form.publicPublish),
        tx.pure.bool(form.eventCreate),
        tx.pure.bool(form.eventPublish),
        tx.pure.bool(form.eventAttach),
        tx.pure.bool(form.eventAdd),
        tx.pure.bool(form.eventRemove),
        tx.pure.bool(form.eventUpdate),
      ],
    });

    submitTx(signAndExecuteTransaction, tx, address, setDigest);
  };

  return (
    <div>
      <h3>Create Container</h3>
      <input placeholder="External ID" onChange={e => setForm({...form, externalId: e.target.value})} />
      <input placeholder="Name" onChange={e => setForm({...form, name: e.target.value})} />
      <input placeholder="Description" onChange={e => setForm({...form, description: e.target.value})} />
      <textarea placeholder="Content" onChange={e => setForm({...form, content: e.target.value})} />
      <button onClick={submit}>Create</button>
      <div>Digest: {digest}</div>
    </div>
  );
}
